"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import { ChevronLeft, ChevronRight, Loader2 } from "lucide-react";
import { Document, Page, pdfjs } from "react-pdf";
import "react-pdf/dist/Page/AnnotationLayer.css";
import "react-pdf/dist/Page/TextLayer.css";
import { cn } from "@/lib/utils";

// Configure PDF.js worker
pdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

interface PDFEmbedClientProps {
    url: string;
    label?: string;
    totalPages?: number | string;
    width?: string;
}

export function PDFEmbedClient({ url, label, totalPages = 10, width }: PDFEmbedClientProps) {
    const [currentPage, setCurrentPage] = useState(1);
    const [numPages, setNumPages] = useState<number | null>(null);
    const [loading, setLoading] = useState(true);
    const [pageWidth, setPageWidth] = useState(0);
    const containerRef = useRef<HTMLDivElement>(null);

    const total = numPages ?? (typeof totalPages === "string" ? parseInt(totalPages, 10) : totalPages);

    const updateWidth = useCallback(() => {
        if (containerRef.current) {
            setPageWidth(containerRef.current.clientWidth);
        }
    }, []);

    useEffect(() => {
        updateWidth();
        const ro = new ResizeObserver(updateWidth);
        if (containerRef.current) ro.observe(containerRef.current);
        return () => ro.disconnect();
    }, [updateWidth]);

    return (
        <div className={cn("my-12 tracking-normal mx-auto", !width && "w-full")} style={{ width }}>
            {/* PDF canvas frame */}
            <div
                ref={containerRef}
                className="relative w-full overflow-hidden rounded-none border border-border-strong/50 shadow-sm bg-slate-50 dark:bg-slate-900/50 flex items-center justify-center min-h-[300px]"
            >
                {/* Loading spinner */}
                {loading && (
                    <div className="absolute inset-0 flex items-center justify-center z-10 bg-slate-50 dark:bg-slate-900/50">
                        <Loader2 size={32} className="animate-spin text-muted" />
                    </div>
                )}

                {/* PDF page */}
                {pageWidth > 0 && (
                    <Document
                        file={url}
                        onLoadSuccess={({ numPages }) => { setNumPages(numPages); setLoading(false); }}
                        onLoadError={() => setLoading(false)}
                        className="w-full relative flex justify-center"
                        loading=""
                    >
                        <Page
                            key={`page_${currentPage}`}
                            pageNumber={currentPage}
                            width={pageWidth}
                            renderTextLayer={false}
                            renderAnnotationLayer={false}
                            className="w-full"
                            // Custom loading state to prevent height collapse jitter during instant page swap
                            loading={
                                <div
                                    className="w-full bg-slate-50/50 dark:bg-slate-900/50"
                                    style={{ aspectRatio: "16/9" }}
                                />
                            }
                        />
                    </Document>
                )}

                {/* Bottom gradient scrim so the pill is always legible */}
                {!loading && (
                    <div className="absolute bottom-0 left-0 right-0 h-20 bg-gradient-to-t from-black/30 to-transparent pointer-events-none z-10" />
                )}

                {/* Floating nav pill — always visible (works on touch/mobile) */}
                {!loading && (
                    <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-20 flex items-center gap-3 bg-background/85 backdrop-blur-md border border-border-strong/50 px-4 py-2 rounded-full shadow-xl">
                        <button
                            onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                            disabled={currentPage === 1}
                            aria-label="Previous page"
                            className="p-1 hover:text-primary disabled:opacity-25 transition-colors active:scale-90 touch-manipulation"
                        >
                            <ChevronLeft size={22} />
                        </button>
                        <span className="text-sm font-bold min-w-[3.5rem] text-center select-none tabular-nums">
                            {currentPage} / {total}
                        </span>
                        <button
                            onClick={() => setCurrentPage(prev => Math.min(prev + 1, total))}
                            disabled={currentPage === total}
                            aria-label="Next page"
                            className="p-1 hover:text-primary disabled:opacity-25 transition-colors active:scale-90 touch-manipulation"
                        >
                            <ChevronRight size={22} />
                        </button>
                    </div>
                )}
            </div>

            {label && (
                <p className="mt-4 text-ds-c1 text-muted opacity-60 font-medium italic text-center">
                    {label}
                </p>
            )}
        </div>
    );
}
